  )
  where c.deleted_at is null
  order by c.id, case when c.item_code = p.code then 0 else 1 end, p.unit_confidence desc
), updated_catalog as (
  update catalog_items c
  set
    normalized_name = left(m.normalized_name, 512),
    selling_unit = upper(m.selling_unit),
    stock_unit = upper(m.stock_unit),
    display_unit = upper(m.canonical_display_unit),
    package_type = upper(m.package_type),
    package_size = m.package_size,
    package_measurement = upper(m.package_measurement),
    package_weight = case when upper(m.package_measurement) = 'KG' then m.weight_per_unit else c.package_weight end,
    conversion_factor = case
      when upper(m.selling_unit) = 'BAG' and m.weight_per_unit is not null then m.weight_per_unit
      else 1
    end,
    unit_confidence = case when m.unit_confidence <= 1 then m.unit_confidence * 100 else m.unit_confidence end,
    smart_classification = 'master_item_profiles_v1',
    ai_detected_unit = upper(m.selling_unit),
    default_unit = case lower(m.selling_unit)
      when 'pcs' then 'piece'
      when 'bag' then 'bag'
      when 'box' then 'box'
      when 'tin' then 'tin'
      when 'kg' then 'kg'
      else c.default_unit
    end,
    default_purchase_unit = case lower(m.rate_dimension)
      when 'pcs' then 'piece'
      when 'bag' then 'bag'
      when 'box' then 'box'
      when 'tin' then 'tin'
      when 'kg' then 'kg'
      else c.default_purchase_unit
    end,
    default_sale_unit = case lower(m.rate_dimension)
      when 'pcs' then 'piece'
      when 'bag' then 'bag'
      when 'box' then 'box'
      when 'tin' then 'tin'
      when 'kg' then 'kg'
      else c.default_sale_unit
    end,
    default_kg_per_bag = case when upper(m.selling_unit) = 'BAG' then m.weight_per_unit else null end,
    default_items_per_box = case when upper(m.selling_unit) = 'BOX' then c.default_items_per_box else null end,
    default_weight_per_tin = case when upper(m.selling_unit) = 'TIN' then c.default_weight_per_tin else null end,
    validation_status = 'unit_profile_verified'
  from matched m
  where c.id = m.catalog_item_id
  returning c.id, c.business_id
), upsert_ai_profiles as (
  insert into ai_item_profiles (id, business_id, catalog_item_id, profile_json, updated_at)
  select gen_random_uuid(), m.business_id, m.catalog_item_id,
    jsonb_build_object(
      'source', 'master_item_profiles_v1',
      'source_name', m.source_name,
      'code', m.code,
      'normalized_name', m.normalized_name,
      'selling_unit', m.selling_unit,
      'stock_unit', m.stock_unit,
      'rate_dimension', m.rate_dimension,
      'package_type', m.package_type,
      'package_size', m.package_size,
      'package_measurement', m.package_measurement,
      'weight_per_unit', m.weight_per_unit,
      'unit_confidence', m.unit_confidence,
      'dedupe_key', m.dedupe_key
    ), now()
  from matched m
  on conflict (business_id, catalog_item_id) do update
  set profile_json = excluded.profile_json,
      updated_at = now()
  returning catalog_item_id
), confidence_logs as (
  insert into unit_confidence_logs (id, business_id, catalog_item_id, source, score, payload_json, created_at)
  select gen_random_uuid(), m.business_id, m.catalog_item_id, 'master_item_profiles_v1',
    case when m.unit_confidence <= 1 then m.unit_confidence * 100 else m.unit_confidence end,
    jsonb_build_object('normalized_name', m.normalized_name, 'selling_unit', m.selling_unit, 'rate_dimension', m.rate_dimension),
    now()
  from matched m
  returning catalog_item_id
)
select
  (select count(*) from profiles) as workbook_profiles,
  (select count(*) from matched) as matched_catalog_items,
  (select count(*) from updated_catalog) as updated_catalog_items,
  (select count(*) from upsert_ai_profiles) as upserted_ai_profiles,
  (select count(*) from confidence_logs) as inserted_confidence_logs;

commit;
